const body = $json.body;

// Extract callback query data
const callbackQuery = body.callback_query;
const callbackData = callbackQuery.data;
const callbackId = callbackQuery.id;
const ownerChatId = callbackQuery.message.chat.id;
const messageId = callbackQuery.message.message_id;

// Parse action and order_id from callback_data
// Format: action_ORDERID  e.g. accept_ORD-123, reject_ORD-123, packed_ORD-123
const underscoreIdx = callbackData.indexOf('_');
const action = callbackData.substring(0, underscoreIdx);
const orderId = callbackData.substring(underscoreIdx + 1);

return [{ json: { 
  action, 
  order_id: orderId, 
  callback_id: callbackId,
  owner_chat_id: ownerChatId,
  message_id: messageId
}}];

// Pass through with order data added
const d = $('Parse Callback').first().json;
const order = $json;

return [{ json: {
  action: d.action,
  order_id: d.order_id,
  callback_id: d.callback_id,
  owner_chat_id: d.owner_chat_id,
  message_id: d.message_id,
  customer_chat_id: order.chat_id,
  shipping_address: order.shipping_address,
  final_order_total: order.final_order_total
}}];

const d = $json;
const action = d.action;
const orderId = d.order_id;

let customerMsg = '';
let ownerMsg = '';
let newStatus = '';
let newKeyboard = null;

if (action === 'accept') {
  newStatus = 'confirmed';
  customerMsg = 'Great news! Your order ' + orderId + ' has been accepted by the store and is being prepared!';
  ownerMsg = 'Order ' + orderId + ' accepted. Update status as you go:';
  newKeyboard = JSON.stringify({
    inline_keyboard: [[
      { text: 'Packed', callback_data: 'packed_' + orderId },
      { text: 'Dispatched', callback_data: 'dispatched_' + orderId },
      { text: 'Delivered', callback_data: 'delivered_' + orderId }
    ]]
  });
}
else if (action === 'reject') {
  newStatus = 'rejected';
  customerMsg = 'Sorry! The store is unable to fulfil your order ' + orderId + ' right now. Please try again later.';
  ownerMsg = 'Order ' + orderId + ' rejected.';
}
else if (action === 'packed') {
  newStatus = 'packed';
  customerMsg = 'Your order ' + orderId + ' has been packed and is ready for pickup!';
  ownerMsg = 'Order ' + orderId + ' marked as packed.';
  newKeyboard = JSON.stringify({
    inline_keyboard: [[
      { text: 'Dispatched', callback_data: 'dispatched_' + orderId },
      { text: 'Delivered', callback_data: 'delivered_' + orderId }
    ]]
  });
}
else if (action === 'dispatched') {
  newStatus = 'dispatched';
  customerMsg = 'Your order ' + orderId + ' is on the way! Estimated delivery soon.';
  ownerMsg = 'Order ' + orderId + ' marked as dispatched.';
  newKeyboard = JSON.stringify({
    inline_keyboard: [[
      { text: 'Delivered', callback_data: 'delivered_' + orderId }
    ]]
  });
}
else if (action === 'delivered') {
  newStatus = 'delivered';
  customerMsg = 'Your order ' + orderId + ' has been delivered. Thank you for shopping with us!';
  ownerMsg = 'Order ' + orderId + ' marked as delivered. Well done!';
}

return [{ json: {
  ...d,
  new_status: newStatus,
  customer_msg: customerMsg,
  owner_reply: ownerMsg,
  new_keyboard: newKeyboard
}}];
